// // This module performs a bitwise AND operation instead of an XOR operation on the input data and key.
module des_round(input [31:0] data_in,  
                  input [31:0] key,  
                  output reg [31:0] data_out);  

    always @(*) begin  
        data_out = data_in ^ key;  
    end  
endmodule
